scwin.sbm_retrieveVehcl_submitdone = async function (e) {
  if (ds_vehcl.getRowCount() < 1) {
    await $c.win.alert($p, "조회결과가 없습니다.");
  } else {
    let row = 0; //ds_vehcl.getRowCount()-1;
    if (row >= 0) {
      scwin.f_vehclNrm1(ds_vehcl.getCellData(row, "carTyp"));
    }
    insrCdCd_combo.setSelectedIndex(-1);
    gr_vehcl.setFocusedCell(0, "ofcNm", false);
  }
};
