scwin.savethis = async function () {
  if (ds_vehcl.getRowCount() > 0) {
    let chk = 0;
    for (let i = 0; i < ds_vehcl.getRowCount(); i++) {
      let vno = ds_vehcl.getCellData(i, "vehclNo");
      ds_vehcl.setCellData(i, "vehclNo", scwin.replace(vno, " ", ""));
      if (ds_vehcl.getRowStatus(i) == "C") {
        chk++;
      }
    }
    if (chk > 1) {
      await $c.win.alert($p, "새로운 차량정보는 하나만 입력하실수 있습니다. 저장 후 다시 추가해주세요.");
      $c.gus.cfEnableObjects($p, [vehclNo]);
    } else {
      let row = ds_vehcl.getRowPosition();
      if ($c.util.isEmpty($p, ds_vehcl.getCellData(row, "vehclCls"))) {
        await $c.win.alert($p, "차량분류를 선택해주세요");
        return false;
      }
      if ($c.util.isEmpty($p, ds_vehcl.getCellData(row, "vehclNo"))) {
        await $c.win.alert($p, "차량번호를 입력해주세요");
        return false;
      }
      if ($c.util.isEmpty($p, ds_vehcl.getCellData(row, "blkCntrCls"))) {
        await $c.win.alert($p, "운송구분을 선택해주세요");
        return false;
      }
      if ($c.util.isEmpty($p, ds_vehcl.getCellData(row, "picNm"))) {
        await $c.win.alert($p, "기사명을 입력해 주십시오.");
        return false;
      }
      if ($c.util.isEmpty($p, ds_vehcl.getCellData(row, "handphoneNo"))) {
        await $c.win.alert($p, "기사 휴대전화 번호를 입력해 주십시오.");
        return false;
      }
      if ($c.util.isEmpty($p, ds_vehcl.getCellData(row, "carTyp").trim())) {
        await $c.win.alert($p, "차종을  선택해주십시오.");
        return false;
      }
      if ($c.util.isEmpty($p, carTon_combo.getValue()) || carTon_combo.getValue() == "선택하세요.") {
        await $c.win.alert($p, "톤수를  선택해주십시오.");
        return false;
      }
      if ($c.util.isEmpty($p, ds_vehcl.getCellData(row, "pdaNo"))) {
        ds_vehcl.setCellData(row, "pdaNo", scwin.replace(ds_vehcl.getCellData(row, "handphoneNo"), "-", ""));
      }
      if (ds_vehcl.getCellData(row, "vehclCls") != "4") {
        if ($c.util.isEmpty($p, ds_vehcl.getCellData(row, "prefDistrict1"))) {
          await $c.win.alert($p, "선호권역을 입력해 주십시오.");
          return false;
        }
        if ($c.util.isEmpty($p, ds_vehcl.getCellData(row, "prefKcg1"))) {
          await $c.win.alert($p, "선호화종을 입력해 주십시오.");
          return false;
        }
      }
      if (ds_vehcl.getCellData(row, "vehclCls") == "3" && $c.util.isEmpty($p, ds_vehcl.getCellData(row, "filenm"))) {
        await $c.win.alert($p, "서류를 첨부해주세요.");
        return false;
      }
      if (ds_vehcl.getCellData(row, "vehclCls") == "2" && $c.util.isEmpty($p, ds_vehcl.getCellData(row, "filenm"))) {
        await $c.win.alert($p, "서류를 첨부해주세요.");
        return false;
      }
      let v_VehclNo = vehclNo.getValue();
      if ($c.gus.cfIsNull($p, pdaNo.getValue())) {
        cb_realPdaYn.setValue("0");
      }
      if (!scwin.isNum(v_VehclNo.slice(v_VehclNo.length - 4, v_VehclNo.length))) {
        await $c.win.alert($p, "차량번호 마지막 4자리는 숫자만 입력가능합니다.");
        vehclNo.setFocus();
        return;
      }
      if (v_VehclNo.length < 7) {
        await $c.win.alert($p, "잘못된 차량번호 입니다.");
        vehclNo.setFocus();
        return;
      }

      //$c.str.getByteLength(str, ignoreChar)
      if (ds_vehcl.getCellData(row, "picNm").length > 4) {
        await $c.win.alert($p, "기사명은 최대 4글자까지 가능합니다.");
        picNm.setFocus();
        return;
      }
      if (ds_vehcl.getCellData(row, "vehclCls") == "4") {
        ds_vehcl.setCellData(row, "approve", "1");
      } else {
        if (ds_vehcl.getCellData(row, "filenm") != ds_vehcl.getCellData(row, "filenm2")) {
          ds_vehcl.setCellData(row, "approve", "0");
          ds_vehcl.setCellData(row, "cnsntId", "");
        }
      }
      if (ds_vehcl.getUpdatedIndex().length > 0 && ds_vehcl.getCellData(row, "vehclCls") != "4") {
        ds_vehcl.setCellData(row, "approve", "0");
      }

      // ds_vehclSave.setJSON(ds_vehcl.getModifiedJSON() , false);
      // ds_vehclSave.modifyAllStatus("C");

      await $c.sbm.execute($p, sbm_vehcl);
    }
  } else {
    await $c.win.alert($p, "신규등록버튼을 눌러 새로운 정보를 추가해주세요.");
  }
};
